CREATE TABLE IF NOT EXISTS admin (                                     admin_id INT PRIMARY KEY AUTO_INCREMENT,                                     admin_email VARCHAR(255) UNIQUE NOT NULL,                                     admin_password_hash VARCHAR(255),                                     admin_role ENUM('restaurant_admin','developer_admin') NOT NULL,                                     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS user ( -- Add an order history references later                                    user_id INT PRIMARY KEY AUTO_INCREMENT,                                    user_email VARCHAR(255) UNIQUE NOT NULL,                                    user_password_hash VARCHAR(255) NOT NULL,                                    user_phone_number INT(10) UNIQUE NULL,                                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);